def gen(rng, size):
    c = max(1, size)
    m = rng.randint(0, min(2 * c, 300))
    connections = []
    for _ in range(m):
        u = rng.randint(1, c)
        v = rng.randint(1, c)
        if u != v:
            connections.append([u, v])
    q = rng.randint(1, 400)
    queries = []
    for _ in range(q):
        if rng.random() < 0.5:
            queries.append([1, rng.randint(1, c)])
        else:
            queries.append([2, rng.randint(1, c)])
    return [c, connections, queries]

