import heapq
class Solution:
    def processQueries(self, c, connections, queries):
        parent = list(range(c + 1))
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        for u, v in connections:
            ru, rv = find(u), find(v)
            if ru != rv:
                parent[ru] = rv
        from collections import defaultdict
        heaps = defaultdict(list)
        for s in range(1, c + 1):
            heaps[find(s)].append(s)
        for r in heaps:
            heapq.heapify(heaps[r])
        online = [True] * (c + 1)
        res = []
        for t, x in queries:
            if t == 2:
                online[x] = False
            else:
                if online[x]:
                    res.append(x)
                    continue
                h = heaps[find(x)]
                while h and not online[h[0]]:
                    heapq.heappop(h)
                res.append(h[0] if h else -1)
        return res

