class MinHeap {
    constructor(arr) { this.a = arr; this._build(); }
    _build() { for (let i = (this.a.length >> 1) - 1; i >= 0; i--) this._down(i); }
    _down(i) { const a = this.a, n = a.length; while (true) { let s = i, l = 2 * i + 1, r = 2 * i + 2; if (l < n && a[l] < a[s]) s = l; if (r < n && a[r] < a[s]) s = r; if (s === i) break; [a[i], a[s]] = [a[s], a[i]]; i = s; } }
    peek() { return this.a.length ? this.a[0] : undefined; }
    pop() { const a = this.a; const t = a[0]; const last = a.pop(); if (a.length) { a[0] = last; this._down(0); } return t; }
    get size() { return this.a.length; }
}
var processQueries = function(c, connections, queries) {
    const parent = new Array(c + 1);
    for (let i = 0; i <= c; i++) parent[i] = i;
    function find(x) { while (parent[x] !== x) { parent[x] = parent[parent[x]]; x = parent[x]; } return x; }
    for (const [u, v] of connections) { const ru = find(u), rv = find(v); if (ru !== rv) parent[ru] = rv; }
    const buckets = new Map();
    for (let s = 1; s <= c; s++) { const r = find(s); if (!buckets.has(r)) buckets.set(r, []); buckets.get(r).push(s); }
    const heaps = new Map();
    for (const [r, arr] of buckets) heaps.set(r, new MinHeap(arr));
    const online = new Array(c + 1).fill(true);
    const res = [];
    for (const [t, x] of queries) {
        if (t === 2) { online[x] = false; }
        else {
            if (online[x]) { res.push(x); continue; }
            const h = heaps.get(find(x));
            while (h.size && !online[h.peek()]) h.pop();
            res.push(h.size ? h.peek() : -1);
        }
    }
    return res;
};
